    return sum(p * q for p, q in zip(prices, quantities))

def process_order(order):
    total_price = 0
    for item in order['items']:
        if item['quantity'] > 0:
            total_price += item['price'] * item['quantity']
    return total_price

def validate_item(item):
    if item['price'] > 0 and item['quantity'] > 0:
        return True
    return False


